import { ApiProperty } from '@nestjs/swagger';
import { Equals, IsIn, IsOptional, IsString } from 'class-validator';

export class ResponseToolSearchCallDto {
  /** The unique ID of the tool search call item. */
  @ApiProperty({
    description: `The unique ID of the tool search call item.`,
    type: 'string',
  })
  @IsString()
  id!: string;

  /** Arguments used for the tool search call. */
  @ApiProperty({ description: `Arguments used for the tool search call.` })
  arguments!: unknown;

  /** The unique ID of the tool search call generated by the model. */
  @ApiProperty({
    description: `The unique ID of the tool search call generated by the model.`,
    type: 'string',
  })
  call_id!: null | string;

  /** Whether tool search was executed by the server or by the client. */
  @ApiProperty({
    description: `Whether tool search was executed by the server or by the client.`,
    enum: ['server', 'client'],
  })
  @IsIn(['server', 'client'])
  execution!: 'server' | 'client';

  /** The status of the tool search call item that was recorded. */
  @ApiProperty({
    description: `The status of the tool search call item that was recorded.`,
    enum: ['in_progress', 'completed', 'incomplete'],
  })
  @IsIn(['in_progress', 'completed', 'incomplete'])
  status!: 'in_progress' | 'completed' | 'incomplete';

  /** The type of the item. Always `tool_search_call`. */
  @ApiProperty({
    description: `The type of the item. Always \`tool_search_call\`.`,
    example: 'tool_search_call',
  })
  @Equals('tool_search_call')
  type!: 'tool_search_call';

  /** The identifier of the actor that created the item. */
  @ApiProperty({
    required: false,
    description: `The identifier of the actor that created the item.`,
    type: 'string',
  })
  @IsOptional()
  @IsString()
  created_by?: string;
}
